1	import { promises as fs } from 'node:fs';
2	import { extname, normalize, resolve, sep } from 'node:path';
3	import { PluginError, makeChatContext, type Plugin } from '@ax/core';
4	
5	const PLUGIN_NAME = '@ax/static-files';
6	
7	// Hardcoded MIME map. Keep small — production deploys serve the channel-web
8	// bundle, which uses a known set of extensions. Adding more isn't free:
9	// content-type sniffing has its own injection surface, so we list extensions
10	// we trust to map deterministically and reject everything else as
11	// application/octet-stream (browsers won't preview-execute it).
12	const MIME_BY_EXT: Record<string, string> = {
13	  '.html': 'text/html; charset=utf-8',
14	  '.htm': 'text/html; charset=utf-8',
15	  '.js': 'application/javascript; charset=utf-8',
16	  '.mjs': 'application/javascript; charset=utf-8',
17	  '.css': 'text/css; charset=utf-8',
18	  '.json': 'application/json; charset=utf-8',
19	  '.txt': 'text/plain; charset=utf-8',
20	  '.map': 'application/json; charset=utf-8',
21	  '.png': 'image/png',
22	  '.jpg': 'image/jpeg',
23	  '.jpeg': 'image/jpeg',
24	  '.gif': 'image/gif',
25	  '.webp': 'image/webp',
26	  '.svg': 'image/svg+xml',
27	  '.ico': 'image/x-icon',
28	  '.woff': 'font/woff',
29	  '.woff2': 'font/woff2',
30	  '.ttf': 'font/ttf',
31	  '.otf': 'font/otf',
32	};
33	
34	// Vite & most bundlers stamp content-hashes into asset filenames
35	// (`assets/foo-3ab19f02.js`). Files matching this pattern get long-lived
36	// cache headers; everything else (notably index.html) gets `no-cache` so
37	// SPA updates propagate. Heuristic, not a security boundary.
38	const HASHED_FILENAME = /[-.][a-f0-9]{8,}\./i;
39	
40	export interface StaticFilesConfig {
41	  /** Absolute path to the directory to serve. Resolved at init. */
42	  dir: string;
43	  /**
44	   * URL pattern, defaults to `'/*'` (serve everything not claimed by an
45	   * earlier exact-match or :param route). Use `/static/*` if you only
46	   * want to serve under a prefix.
47	   */
48	  mountPath?: string;
49	  /**
50	   * Single-page-app fallback:
51	   *   - `false` (default): unknown paths → 404
52	   *   - `true`: unknown paths → serve `<dir>/index.html`
53	   *   - string: serve `<dir>/<that file>`
54	   */
55	  spaFallback?: boolean | string;
56	}
57	
58	interface RegisterRouteResult {
59	  unregister(): void;
60	}
61	
62	// Structural minimum we need from @ax/http-server's adapter. Mirrors the
63	// pattern @ax/auth-oidc uses with HttpRequestLike: I2 forbids importing
64	// from @ax/http-server, so we duck-type the surface here.
65	interface HttpRequestLike {
66	  readonly headers: Record<string, string>;
67	  readonly params: Record<string, string>;
68	}
69	
70	interface HttpResponseLike {
71	  status(n: number): HttpResponseLike;
72	  header(name: string, value: string): HttpResponseLike;
73	  body(buf: Buffer, contentType?: string): void;
74	  end(): void;
75	  json(v: unknown): void;
76	}
77	
78	type HttpRouteHandlerLike = (
79	  req: HttpRequestLike,
80	  res: HttpResponseLike,
81	) => Promise<void>;
82	
83	interface RegisterRouteInput {
84	  method: 'GET';
85	  path: string;
86	  handler: HttpRouteHandlerLike;
87	}
88	
89	export function createStaticFilesPlugin(config: StaticFilesConfig): Plugin {
90	  const root = resolve(config.dir);
91	  const mountPath = config.mountPath ?? '/*';
92	  const fallbackFile =
93	    config.spaFallback === true
94	      ? 'index.html'
95	      : typeof config.spaFallback === 'string'
96	        ? config.spaFallback
97	        : null;
98	
99	  let unregister: (() => void) | undefined;
100	
101	  return {
102	    manifest: {
103	      name: PLUGIN_NAME,
104	      version: '0.0.0',
105	      registers: [],
106	      calls: ['http:register-route'],
107	      subscribes: [],
108	    },
109	
110	    async init({ bus }) {
111	      // Verify dir exists at boot — fail fast so a missing build directory
112	      // doesn't show up as 404s after the first request.
113	      let stat;
114	      try {
115	        stat = await fs.stat(root);
116	      } catch (err) {
117	        throw new PluginError({
118	          code: 'invalid-config',
119	          plugin: PLUGIN_NAME,
120	          message: `static-files dir does not exist: ${root}`,
121	          cause: err,
122	        });
123	      }
124	      if (!stat.isDirectory()) {
125	        throw new PluginError({
126	          code: 'invalid-config',
127	          plugin: PLUGIN_NAME,
128	          message: `static-files dir is not a directory: ${root}`,
129	        });
130	      }
131	
132	      const ctx = makeChatContext({
133	        sessionId: 'static-files',
134	        agentId: 'static-files',
135	        userId: 'system',
136	      });
137	
138	      const handler: HttpRouteHandlerLike = async (req, res) => {
139	        const splat = req.params['*'] ?? '';
140	        const ifNoneMatch = req.headers['if-none-match'];
141	
142	        const direct = await tryServe(splat, ifNoneMatch, res);
143	        if (direct === 'served' || direct === '304') return;
144	
145	        if (fallbackFile !== null) {
146	          const fb = await tryServe(fallbackFile, ifNoneMatch, res);
147	          if (fb === 'served' || fb === '304') return;
148	        }
149	
150	        res.status(404).json({ error: 'not-found' });
151	      };
152	
153	      const result = await bus.call<RegisterRouteInput, RegisterRouteResult>(
154	        'http:register-route',
155	        ctx,
156	        { method: 'GET', path: mountPath, handler },
157	      );
158	      unregister = result.unregister;
159	    },
160	
161	    async shutdown() {
162	      unregister?.();
163	      unregister = undefined;
164	    },
165	  };
166	
167	  // ---------------------------------------------------------------------
168	  // Internal helpers
169	  // ---------------------------------------------------------------------
170	
171	  async function tryServe(
172	    relPath: string,
173	    ifNoneMatch: string | undefined,
174	    res: HttpResponseLike,
175	  ): Promise<'served' | '304' | 'miss'> {
176	    // Strip a single leading '/' if present — the splat captures
177	    // everything after the prefix, including the leading slash on `/*`.
178	    const cleaned = relPath.replace(/^\/+/, '');
179	
180	    // Resolve against the configured root and verify the result stays
181	    // inside it. `resolve` does NOT follow symlinks; that's intentional —
182	    // a symlink target outside `root` would be caught by the prefix
183	    // check. (We never call `realpath`.)
184	    const candidate = normalize(resolve(root, cleaned));
185	    const rootSep = root.endsWith(sep) ? root : root + sep;
186	    if (candidate !== root && !candidate.startsWith(rootSep)) {
187	      // Path traversal attempt — return 'miss' so the caller's fallback
188	      // logic fires. From the attacker's perspective this is
189	      // indistinguishable from "file doesn't exist".
190	      return 'miss';
191	    }
192	
193	    let stat;
194	    try {
195	      stat = await fs.stat(candidate);
196	    } catch {
197	      return 'miss';
198	    }
199	    if (!stat.isFile()) return 'miss';
200	
201	    const ext = extname(candidate).toLowerCase();
202	    const mime = MIME_BY_EXT[ext] ?? 'application/octet-stream';
203	
204	    // Weak ETag = `<size-hex>-<mtime-hex>`. Cheap to compute and good
205	    // enough for cache validation; clients only need a stable value
206	    // that changes when the file changes.
207	    const etag = `W/"${stat.size.toString(16)}-${Math.floor(stat.mtimeMs).toString(16)}"`;
208	
209	    if (ifNoneMatch !== undefined && ifNoneMatch === etag) {
210	      res.status(304).header('etag', etag).end();
211	      return '304';
212	    }
213	
214	    const body = await fs.readFile(candidate);
215	
216	    const cacheControl = HASHED_FILENAME.test(candidate)
217	      ? 'public, max-age=31536000, immutable'
218	      : 'no-cache';
219	
220	    res
221	      .status(200)
222	      .header('etag', etag)
223	      .header('cache-control', cacheControl)
224	      .body(body, mime);
225	    return 'served';
226	  }
227	}
